mapper.insert:
INSERT INTO sys_monitor_rule (
    rule_name, attack_type, rule_content, description, risk_level, enabled, priority,
    hit_count, last_hit_time, create_time, update_time
) VALUES (
    #{ruleName}, #{attackType}, #{ruleContent}, #{description}, #{riskLevel}, #{enabled}, #{priority},
    COALESCE(#{hitCount}, 0), #{lastHitTime}, #{createTime}, #{updateTime}
)

mapper.select:
SELECT 
FROM sys_monitor_rule


        AND rule_name LIKE CONCAT('%', #{ruleName}, '%')


        AND attack_type = #{attackType}


        AND enabled = #{enabled}


ORDER BY priority ASC, create_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM sys_monitor_rule


        AND rule_name LIKE CONCAT('%', #{ruleName}, '%')


        AND attack_type = #{attackType}


        AND enabled = #{enabled}




        ORDER BY id ${sortOrder}


        ORDER BY rule_name ${sortOrder}


        ORDER BY attack_type ${sortOrder}


        ORDER BY 
        CASE risk_level
            WHEN 'CRITICAL' THEN 1
            WHEN 'HIGH' THEN 2
            WHEN 'MEDIUM' THEN 3
            WHEN 'LOW' THEN 4
            ELSE 5
        END ${sortOrder}


        ORDER BY enabled ${sortOrder}


        ORDER BY id DESC


LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM sys_monitor_rule


        AND rule_name LIKE CONCAT('%', #{ruleName}, '%')


        AND attack_type = #{attackType}


        AND enabled = #{enabled}

mapper.update:
UPDATE sys_monitor_rule
SET enabled = #{enabled}, update_time = NOW()
WHERE id = #{id}

UPDATE sys_monitor_rule
SET hit_count = #{hitCount}, last_hit_time = NOW(), update_time = NOW()
WHERE id = #{id}
